311	int main(int argc, char* const argv[]) {
312	#ifdef __WINDOWS__
313	    // Enable UTF-8 output and VT100 escape sequences on Windows console
314	    SetConsoleOutputCP(65001);
315	    SetConsoleCP(65001);
316	    HANDLE hOut = GetStdHandle(STD_OUTPUT_HANDLE);
317	    DWORD dwMode = 0;
318	    GetConsoleMode(hOut, &dwMode);
319	    SetConsoleMode(hOut, dwMode | ENABLE_VIRTUAL_TERMINAL_PROCESSING);
320	
321	    signal(SIGINT, WorkThread::Stop);
322	    signal(SIGTERM, WorkThread::Stop);
323	#else
324	    struct sigaction stact;
325	    memset(&stact, 0, sizeof(stact));
326	    stact.sa_handler = WorkThread::Stop;
327	    sigaction(SIGINT, &stact, NULL);
328	    sigaction(SIGTERM, &stact, NULL);
329	#endif
330	
331	    CommandManager::Init();
332	    CommandManager::PushInlineCommand(new QuitCommand());
333	
334	    // Pre-scan for --mcp: stdout is the JSON-RPC channel, so suppress all
335	    // diagnostic output during startup (copyright, core loading messages).
336	    bool is_mcp = false;
337	    for (int i = 1; i < argc; i++) {
338	        if (strcmp(argv[i], "--mcp") == 0) { is_mcp = true; break; }
339	    }
340	
341	    int preload_saved_fd = -1;
342	    if (is_mcp) {
343	        preload_saved_fd = dup(fileno(stdout));
344	        int null_fd = open("/dev/null", O_WRONLY);
345	        dup2(null_fd, fileno(stdout));
346	        close(null_fd);
347	    } else {
348	        show_copyright();
349	#if defined(__AOSP_PARSER__)
350	        show_compat_android_version();
351	#endif
352	    }
353	
354	    if (command_preload(argc, argv) < 0) {
355	        if (preload_saved_fd >= 0)
356	            close(preload_saved_fd);
357	        return 0;
358	    }
359	
360	    // Restore stdout and launch MCP event loop.
361	    if (preload_saved_fd >= 0) {
362	        fflush(stdout);   // drain stdio buffer → /dev/null before restoring fd
363	        dup2(preload_saved_fd, fileno(stdout));
364	        close(preload_saved_fd);
365	        McpServer mcp;
366	        mcp.start();
367	        return 0;
368	    }
369	
370	    UiThread ui;
371	    while (1) {
372	        std::string cmdline;
373	        ui.GetCommand(&cmdline);
374	        WorkThread work(cmdline);
375	        work.Join();
376	        ui.Wake();
377	    }
378	    ui.Join();
379	    return 0;
380	}
