156	int CommandManager::Execute(const char* cmd, int argc, char* const argv[]) {
157	    if (!cmd) return -1;
158	    Command* command = FindCommand(cmd);
159	    if (command) {
160	        try {
161	            ShellCommand* shell = nullptr;
162	            int position = 0;
163	            bool writeout = false;
164	            for (int i = 0; i < argc; ++i) {
165	                if (!strcmp(argv[i], "|")) {
166	                    ++i;
167	                    if (i < argc) {
168	                        shell = reinterpret_cast<ShellCommand *>(FindCommand("shell"));
169	                        position = i;
170	                        break;
171	                    }
172	                } else if (!strcmp(argv[i], ">")) {
173	                    ++i;
174	                    if (i < argc) {
175	                        position = i;
176	                        writeout = true;
177	                        break;
178	                    }
179	                }
180	            }
181	
182	            if (shell) {
183	                int nargc = position - 1;
184	                auto callback = [&command, nargc, &argv]() {
185	                    command->execute(nargc, argv);
186	                };
187	                shell->main(argc - nargc, &argv[nargc], callback);
188	                return 0;
189	            } else if (writeout) {
190	                bool light = Logger::IsLight();
191	                Logger::SetHighLight(false);
192	                int fd = Utils::FreopenWrite(argv[position]);
193	                int nargc = position - 1;
194	                command->execute(nargc, argv);
195	                Utils::CloseWriteout(fd);
196	                Logger::SetHighLight(light);
197	                return 0;
198	            }
199	            return command->execute(argc, argv);
200	        } catch (InvalidAddressException& e) {
201	            LOGE("%s\n", e.what());
202	        }
203	    } else {
204	        LOGW("Not found command (%s).\n", cmd);
205	    }
206	    return 0;
207	}
208	
209	void CommandManager::ForeachCommand(std::function<bool (Command *)> callback) {
210	    INSTANCE->foreachInlineCommand(callback);
211	    INSTANCE->foreachExtendCommand(callback);
212	}
213	
214	Command* CommandManager::FindCommand(const char* cmd) {
215	    Command* result = nullptr;
216	    auto callback = [cmd, &result](Command* command) -> bool {
217	        if (command->get() == cmd || command->shortcut() == cmd) {
218	            result = command;
219	            return true;
220	        }
221	        return false;
222	    };
223	    ForeachCommand(callback);
224	    return result;
225	}
226	
227	void CommandManager::foreachInlineCommand(std::function<bool (Command *)> callback) {
228	    for (const auto& command : inline_commands)
229	        if (callback(command.get()))
230	            break;
231	}
232	
233	void CommandManager::foreachExtendCommand(std::function<bool (Command *)> callback) {
234	    for (const auto& command : extend_commands)
235	        if (callback(command.get()))
236	            break;
237	}
238	
239	void CommandManager::PushInlineCommand(Command* command) {
240	    INSTANCE->pushInlineCommand(command);
241	}
242	
243	void CommandManager::pushInlineCommand(Command* command) {
244	    std::unique_ptr<Command> ref(command);
245	    inline_commands.push_back(std::move(ref));
246	}
247	
248	int CommandManager::PushExtendCommand(Command* command) {
249	    return INSTANCE->pushExtendCommand(command);
250	}
251	
252	int CommandManager::pushExtendCommand(Command* command) {
253	    if (!command)
254	        return 0;
255	
256	    if (!plugin->GetCurrent())
257	        return 0;
258	
259	    std::unique_ptr<Command> ref(command);
260	    Command* tmp = FindCommand(command->get().c_str());
261	    if (tmp) {
262	        LOGW("plugin \"%s\" exist.\n", command->get().c_str());
263	        return 0;
264	    }
265	
266	    extend_commands.push_back(std::move(ref));
267	    plugin->GetCurrent()->HookCommand(command);
268	    return 1;
269	}
270	
271	int CommandManager::PopExtendCommand(Command* command) {
272	    return INSTANCE->popExtendCommand(command);
273	}
274	
275	int CommandManager::popExtendCommand(Command* command) {
276	    std::vector<std::unique_ptr<Command>>::iterator iter;
277	    for (iter = extend_commands.begin(); iter != extend_commands.end(); iter++) {
278	        if (iter->get() == command) {
279	            extend_commands.erase(iter);
280	            return 1;
281	        }
282	    }
283	    return 0;
284	}
